import React, { useState, useEffect } from 'react';
import { Package, Bike, Home } from 'lucide-react';

const SeguimientoPedido = ({ pedido, onFinalizar }) => {
  const [fase, setFase] = useState(1);
  const [porcentajeCamino, setPorcentajeCamino] = useState(0);

  useEffect(() => {
    // Simulación del avance (0% a 100%)
    const intervalo = setInterval(() => {
      setPorcentajeCamino(prev => {
        if (prev >= 100) {
          clearInterval(intervalo);
          return 100;
        }
        return prev + 1;
      });
    }, 150); // 15 segundos aprox para completar el recorrido

    const t1 = setTimeout(() => setFase(2), 2000); // Sale del local a los 2s
    const t2 = setTimeout(() => {
      setFase(3); // Llega al destino
      setTimeout(() => { if (onFinalizar) onFinalizar(pedido.id); }, 3000);
    }, 15000);

    return () => {
      clearInterval(intervalo);
      clearTimeout(t1);
      clearTimeout(t2);
    };
  }, [pedido.id, onFinalizar]);

  return (
    <div style={card}>
      <div style={header}>
        <div>
          <strong style={{ display: 'block' }}>Pedido #{pedido.id.slice(-6)}</strong>
          <small style={{ color: '#64748b' }}>Destino: {pedido.direccion}</small>
        </div>
        <div style={estadoBadge(fase)}>
          {fase === 1 ? 'Preparando' : fase === 2 ? 'En Camino' : '¡Entregado!'}
        </div>
      </div>

      {/* --- NUEVA BARRA DE CARGA CON MOTITO --- */}
      <div style={pistaContenedor}>
        <div style={iconoSucursal}><Package size={24} /></div>
        
        <div style={lineaGris}>
          {/* Parte de la línea que se va pintando de naranja */}
          <div style={{ ...lineaNaranja, width: `${porcentajeCamino}%` }} />
          
          {/* La motito que se desplaza */}
          <div style={{ ...motoContenedor, left: `${porcentajeCamino}%` }}>
            <Bike size={28} color="#e67e22" fill="#fff" />
            <div style={humo}></div>
          </div>
        </div>

        <div style={iconoCasa}><Home size={24} /></div>
      </div>
      {/* --------------------------------------- */}

      <div style={footerInfo}>
        <span>Distancia: <strong>{pedido.distancia} km</strong></span>
        <span>
            {fase === 3 
                ? <span style={{color: '#27ae60'}}>¡Llegó a destino!</span> 
                : `Llegada en: ${Math.max(1, 10 - Math.round(porcentajeCamino/10))} min`
            }
        </span>
      </div>
    </div>
  );
};

/* --- ESTILOS ACTUALIZADOS --- */
const card = { background: 'white', padding: '25px', borderRadius: '24px', border: '1px solid #e2e8f0', marginBottom: '20px', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' };
const header = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' };
const estadoBadge = (fase) => ({
  padding: '6px 12px',
  borderRadius: '20px',
  fontSize: '0.8rem',
  fontWeight: 'bold',
  background: fase === 3 ? '#dcfce7' : '#fef3c7',
  color: fase === 3 ? '#166534' : '#92400e'
});

// Estilos de la Pista (Barra de progreso)
const pistaContenedor = { 
  display: 'flex', 
  alignItems: 'center', 
  gap: '15px', 
  height: '80px', 
  margin: '20px 0', 
  position: 'relative' 
};

const lineaGris = { 
  flex: 1, 
  height: '6px', 
  background: '#e2e8f0', 
  borderRadius: '10px', 
  position: 'relative' 
};

const lineaNaranja = { 
  position: 'absolute', 
  height: '100%', 
  background: '#e67e22', 
  borderRadius: '10px', 
  transition: 'width 0.2s linear' 
};

const motoContenedor = { 
  position: 'absolute', 
  top: '-12px', 
  transform: 'translateX(-50%)', 
  transition: 'left 0.2s linear',
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center'
};

const iconoSucursal = { color: '#64748b' };
const iconoCasa = { color: '#e67e22' };

const footerInfo = { 
  marginTop: '20px', 
  display: 'flex', 
  justifyContent: 'space-between', 
  fontSize: '0.85rem', 
  color: '#475569', 
  borderTop: '1px solid #f1f5f9', 
  paddingTop: '15px' 
};

const humo = { width: '4px', height: '4px', background: '#cbd5e1', borderRadius: '50%', marginTop: '2px' };

export default SeguimientoPedido;
